const port = Number(Bun.env.PORT ?? 3000);

const TTL_MS = 300;
const NEGATIVE_TTL_MS = 150;
const MAX_ENTRIES = 20;
const COMPUTE_DELAY_MS = 10;

type CacheEntry = {
  key: string;
  value?: string;
  error?: boolean;
  computedAt: number;
  negativeUntil?: number;
};

const cache = new Map<string, CacheEntry>();
const invocationCounts = new Map<string, number>();
const inflight = new Map<string, Promise<CacheEntry>>();

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function hashValue(key: string): string {
  let h = 0;
  for (let i = 0; i < key.length; i += 1) {
    h = (h * 31 + key.charCodeAt(i)) >>> 0;
  }
  return `v-${h.toString(16)}`;
}

function shouldFail(key: string): boolean {
  return key.startsWith("fail-");
}

function touchEntry(key: string, entry: CacheEntry): void {
  cache.delete(key);
  cache.set(key, entry);
  if (cache.size > MAX_ENTRIES) {
    const oldest = cache.keys().next().value;
    if (oldest) cache.delete(oldest);
  }
}

function incrementInvocation(key: string): void {
  invocationCounts.set(key, (invocationCounts.get(key) ?? 0) + 1);
}

async function runCompute(key: string): Promise<CacheEntry> {
  incrementInvocation(key);
  await sleep(COMPUTE_DELAY_MS);
  if (shouldFail(key)) {
    const entry: CacheEntry = {
      key,
      error: true,
      computedAt: Date.now(),
      negativeUntil: Date.now() + NEGATIVE_TTL_MS,
    };
    touchEntry(key, entry);
    return entry;
  }
  const entry: CacheEntry = { key, value: hashValue(key), computedAt: Date.now() };
  touchEntry(key, entry);
  return entry;
}

function getInflight(key: string): Promise<CacheEntry> {
  const existing = inflight.get(key);
  if (existing) return existing;
  const promise = runCompute(key).finally(() => {
    inflight.delete(key);
  });
  inflight.set(key, promise);
  return promise;
}

function isFresh(entry: CacheEntry, now: number): boolean {
  if (entry.error) {
    return entry.negativeUntil !== undefined && now < entry.negativeUntil;
  }
  return now - entry.computedAt < TTL_MS;
}

function isStale(entry: CacheEntry, now: number): boolean {
  if (entry.error) {
    return entry.negativeUntil !== undefined && now >= entry.negativeUntil;
  }
  return now - entry.computedAt >= TTL_MS;
}

async function getCompute(key: string): Promise<{ status: number; body: object }> {
  const now = Date.now();
  const cached = cache.get(key);

  if (cached && isFresh(cached, now)) {
    if (cached.error) {
      return { status: 503, body: { error: "compute_failed", cached: true } };
    }
    return { status: 200, body: { value: cached.value, cached: true } };
  }

  if (cached && isStale(cached, now) && !cached.error) {
    if (!inflight.has(key)) {
      void getInflight(key);
    }
    return { status: 200, body: { value: cached.value, cached: true } };
  }

  if (cached && cached.error && isStale(cached, now)) {
    const entry = await getInflight(key);
    if (entry.error) {
      return { status: 503, body: { error: "compute_failed", cached: false } };
    }
    return { status: 200, body: { value: entry.value, cached: false } };
  }

  const entry = await getInflight(key);
  if (entry.error) {
    return { status: 503, body: { error: "compute_failed", cached: false } };
  }
  return { status: 200, body: { value: entry.value, cached: false } };
}

Bun.serve({
  port,
  async fetch(request) {
    const url = new URL(request.url);

    if (request.method === "GET" && url.pathname === "/healthz") {
      return Response.json({ ok: true }, { status: 200 });
    }

    if (request.method === "GET" && url.pathname === "/stats") {
      const invocations: Record<string, number> = {};
      for (const [key, count] of invocationCounts) {
        invocations[key] = count;
      }
      return Response.json({ invocations }, { status: 200 });
    }

    const computeMatch = /^\/compute\/(.+)$/.exec(url.pathname);
    if (request.method === "GET" && computeMatch) {
      const key = decodeURIComponent(computeMatch[1]!);
      if (!key) {
        return Response.json({ error: "invalid_key" }, { status: 400 });
      }
      const result = await getCompute(key);
      return Response.json(result.body, { status: result.status });
    }

    return Response.json({ error: "not_found" }, { status: 404 });
  },
});

console.log(`cache-stampede reference listening on ${port}`);
BUN_BENCH_SOLUTION_EOF
